#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long H; scanf("%d %lld", &N, &H);
        long long *A = (long long*)malloc(N*sizeof(long long));
        long long maxA = 0;
        for(int i=0;i<N;i++){
            scanf("%lld", &A[i]);
            if(A[i]>maxA) maxA = A[i];
        }
        long long lo = 1, hi = maxA, ans = maxA;
        while(lo<=hi){
            long long mid = lo + (hi-lo)/2;
            __int128 total = 0; // use 128 to avoid overflow in intermediate sum
            for(int i=0;i<N;i++){
                total += (A[i] + mid - 1) / mid;
                if(total > H) break;
            }
            if(total <= H){
                ans = mid;
                hi = mid - 1;
            }else{
                lo = mid + 1;
            }
        }
        printf("%lld\n", ans);
        free(A);
    }
    return 0;
}

