#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); H = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        lo, hi = 1, max(A)
        ans = hi
        while lo <= hi:
            mid = (lo + hi) // 2
            hours = 0
            for x in A:
                hours += (x + mid - 1) // mid
                if hours > H:
                    break
            if hours <= H:
                ans = mid
                hi = mid - 1
            else:
                lo = mid + 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

